import { describe, expect, it } from 'vitest';
import { createTestHarness, type TestHarnessAuthorResponse } from '@simodelne/pgas-server/testing.js';
import { createProposalOpsProgramEntry } from '../src/programs/proposal-ops/registration.js';

describe('generated program smoke', () => {
  it('runs Proposal Ops through the deterministic completion path without stub output', async () => {
    const harness = await createTestHarness(createProposalOpsProgramEntry(), {
      programName: 'proposal-ops',
      defaultChannel: 'user_text',
      authorResponses: [
        effect('begin_work', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_fee_modeling', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_crm_lookup', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_brief_summary', {
          result_json: JSON.stringify({"assessment":"The recorded brief_summary facts support proceeding.","recommended_action":"proceed","confidence":"high","key_findings":["recorded facts are consistent"]}),
          items_json: JSON.stringify(["brief_summary:action:proceed","brief_summary:confidence:high"]),
          assessment: "The recorded brief_summary facts support proceeding.",
          recommended_action: "proceed",
          confidence: "high",
          key_findings: "[\"recorded facts are consistent\"]",
        }, 'widget_output'),
      ],
    });

    try {
      await harness.trigger('start generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      const snapshot = await harness.snapshot();
      expect(snapshot.mode).toBe('complete');
      const serialized = JSON.stringify(snapshot.domain).toLowerCase();
      expect(serialized).not.toContain('stage_action_stub');
      expect(serialized).not.toContain('"todo"');
      expect(serialized).toContain('in_memory_mock');
    } finally {
      await harness.close();
    }
  });
});

function effect(name: string, payload: Record<string, unknown>, channel?: string): TestHarnessAuthorResponse {
  return { actions: [{ kind: 'EffectAction', name, channel: channel ?? (name === 'begin_work' ? 'widget_output' : 'stage_output'), payload }] };
}
